#include <bits/stdc++.h>
using namespace std;

int L[100005], R[100005];
vector<int> result;

void postorder(int x) {
    if (x == -1) return;
    postorder(L[x]);
    postorder(R[x]);
    result.push_back(x);
}

int main() {
    ios_base::sync_with_stdio(false); cin.tie(NULL);
    int n; cin >> n;
    for (int i = 1; i <= n; i++) { L[i] = -1; R[i] = -1; }
    for (int i = 0; i < n; i++) {
        int x, l, r; cin >> x >> l >> r;
        L[x] = l; R[x] = r;
    }
    postorder(1);
    for (size_t i = 0; i < result.size(); i++) {
        if (i) cout << ' ';
        cout << result[i];
    }
    cout << "\n";
    return 0;
}
